@inherits LayoutComponentBase
@using Blazored.Toast
@using Blazored.Toast.Configuration
@using SamarPlanner.Web.Services
@inject NavigationManager NavigationManager

<div class="goal-layout">
    <div class="goal-header">
        <div class="goal-nav">
            <NavLink href="/goals" class="nav-link" ActiveClass="active" Match="NavLinkMatch.All">
                <i class="bi bi-list-ul"></i> همه
            </NavLink>
            <NavLink href="/goals/active" class="nav-link" ActiveClass="active">
                <i class="bi bi-play-circle"></i> فعال
            </NavLink>
            <NavLink href="/goals/completed" class="nav-link" ActiveClass="active">
                <i class="bi bi-check2-circle"></i> بسته شده
            </NavLink>
            <div class="nav-dropdown">
                <button class="nav-link nav-dropdown-toggle" @onclick="ToggleDropdown">
                    <i class="bi bi-three-dots-vertical"></i>
                </button>
                @if (_showDropdown)
                {
                    <div class="nav-dropdown-menu" @onclick:stopPropagation>
                        <NavLink href="/goals/deleted" class="dropdown-item" ActiveClass="active">
                            <i class="bi bi-trash3"></i> حذف شده‌ها
                        </NavLink>
                    </div>
                }
            </div>
        </div>
    </div>

    <main class="goal-content">
        @Body
    </main>

    <div class="fab-container">
        <button class="btn-fab" @onclick="OpenAddGoalModal">
            <i class="bi bi-plus-lg"></i>
        </button>
    </div>
</div>

@if (_showAddGoalModal)
{
    <div class="modal-overlay">
        <div class="modal-content" @onclick:stopPropagation>
            <div class="modal-header">
                <h5>هدف جدید</h5>
                <button class="btn-close" @onclick="CloseModal"></button>
            </div>
            <div class="modal-body">
                <AddGoalForm OnGoalAdded="OnGoalAdded" />
            </div>
        </div>
    </div>
}

<BlazoredToasts Position="ToastPosition.TopRight" />

@code {
    private bool _showAddGoalModal = false;
    private bool _showDropdown = false;

    private void OpenAddGoalModal()
    {
        _showAddGoalModal = true;
    }

    private void CloseModal()
    {
        _showAddGoalModal = false;
    }

    private Task OnGoalAdded()
    {
        CloseModal();
        NavigationManager.NavigateTo(NavigationManager.Uri, forceLoad: true);
        return Task.CompletedTask;
    }

    private void ToggleDropdown()
    {
        _showDropdown = !_showDropdown;
    }
}

